import pytest
from hypothesis import given
from hypothesis import strategies as st
from my.command import check_available
from my.error import CommandNotFound


@st.composite
def commands_containing_foo(draw) -> list[str]:
    """Génère une liste de commandes contenant 'foo'"""
    commands = draw(st.lists(st.text(min_size=1)))

    index = draw(st.integers(min_value=0, max_value=len(commands)))
    commands[index:index] = ["foo"]

    return commands


def describe_function_check_available():
    """la fonction check_available()"""

    @given(commands=st.lists(st.text()))
    def it_finds_executables(commands: list[str], mocker) -> None:
        """ne fait rien lorsque les exécutables sont trouvés"""

        # `which` trouve toujours l'exécutable et retourne simplement le nom
        mocker.patch("my.command.which", lambda x: x)

        check_available(*commands)

    @given(commands=commands_containing_foo())
    def it_raises_exception(commands: list[str], mocker) -> None:
        """lève une exception lorsque l'un des exécutables est introuvable"""

        # `which` ne trouve pas l'exécutable "foo"
        mocker.patch("my.command.which", lambda x: None if x == "foo" else x)

        with pytest.raises(CommandNotFound):
            check_available(*commands)
